# @cctt_verify {"v":2,"sym":"sympy.solvers.diophantine.tests.test_diophantine.is_pell_transformation_ok","kind":"function","src_hash":"21b20a2a33e29aef","in":{"base":"Any","pred":"hasattr(eq, 'subs')"},"out":{"base":"Any"},"spec":{"lhs":"is_pell_transformation_ok(eq)","rhs":"<unspecified:is_pell_transformation_ok>","over":{"base":"Any","pred":"hasattr(eq, 'subs')"},"name":"is_pell_transformation_ok_correct"},"guarantee":"test whether x*y, x, or y terms are present in the equation after transforming the equation using the transformation returned by transformation_to_pell()","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.diophantine.tests.test_diophantine.is_pell_transformation_ok_correct","statement":"Path(is_pell_transformation_ok(x), test whether x*y, x, or y terms are present in the equation after transforming the equation using the transformation returned by transformation_to_pell())"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4f4b6bbbd59ed49c","spec_source":"static","formal_spec":{"source":"static","strength":"trivial","requires":["hasattr(eq, 'subs')"],"pure":false,"effects":{"effect_type":"reads_state","reads":["eq.subs"]}},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.3,"verdict_class":"assumed","binding":true}}
def is_pell_transformation_ok(eq):
    """
    Test whether X*Y, X, or Y terms are present in the equation
    after transforming the equation using the transformation returned
    by transformation_to_pell(). If they are not present we are good.
    Moreover, coefficient of X**2 should be a divisor of coefficient of
    Y**2 and the constant term.
    """
    A, B = transformation_to_DN(eq)
    u = (A*Matrix([X, Y]) + B)[0]
    v = (A*Matrix([X, Y]) + B)[1]
    simplified = diop_simplify(eq.subs(zip((x, y), (u, v))))

    coeff = dict([reversed(t.as_independent(*[X, Y])) for t in simplified.args])

    for term in [X*Y, X, Y]:
        if term in coeff.keys():
            return False

    for term in [X**2, Y**2, 1]:
        if term not in coeff.keys():
            coeff[term] = 0

    if coeff[X**2] != 0:
        return divisible(coeff[Y**2], coeff[X**2]) and \
        divisible(coeff[1], coeff[X**2])

    return True


